import{_ as t,o as s,c as o,a2 as p}from"./chunks/framework.CkaEw-3u.js";const r="/mug-typography-docs/image/global-char-part.webp",m=JSON.parse('{"title":"基本的な考え方","description":"","frontmatter":{"title":"基本的な考え方"},"headers":[],"relativePath":"guide/core-concepts.md","filePath":"guide/core-concepts.md"}'),n={name:"guide/core-concepts.md"};function e(i,a,l,d,c,g){return s(),o("div",null,[...a[0]||(a[0]=[p('<h1 id="基本的な考え方" tabindex="-1">基本的な考え方 <a class="header-anchor" href="#基本的な考え方" aria-label="Permalink to &quot;基本的な考え方&quot;">​</a></h1><p>このプラグインには、操作の対象となる <strong>3 つのレベル</strong> があります。</p><table tabindex="0"><thead><tr><th>レベル</th><th>説明</th><th>例</th></tr></thead><tbody><tr><td><strong>グローバル</strong></td><td>テキスト全体に一括で適用される設定</td><td>フォント、全体の位置・回転・スケール</td></tr><tr><td><strong>キャラクター</strong></td><td>1 文字ごとに個別に適用できる設定</td><td>特定の文字を大きくする、色を変える</td></tr><tr><td><strong>パーツ</strong></td><td>文字を構成するパス要素ごとの設定</td><td>「だ」の点だけを動かす</td></tr></tbody></table><p>たとえば、グローバルで全体を右に移動しつつ、特定の文字だけをさらに上にずらし、その文字の中の特定パーツだけを回転させる、といった重ね合わせが可能です。</p><h2 id="設定値の伝播と合成" tabindex="-1">設定値の伝播と合成 <a class="header-anchor" href="#設定値の伝播と合成" aria-label="Permalink to &quot;設定値の伝播と合成&quot;">​</a></h2><p>各レベルの設定値は <strong>上位から下位へ順に伝播し、すべてが合成された結果</strong> として描画されます。</p><div class="propagation-formula"><div class="propagation-term"><span class="propagation-symbol">M<sub>Global</sub></span><span class="propagation-value">回転 +10°</span><small>テキスト全体のピボットを中心に</small></div><span class="propagation-op">×</span><div class="propagation-term"><span class="propagation-symbol">M<sub>Character</sub></span><span class="propagation-value">回転 +15°</span><small>その結果へ、文字のピボットを中心に</small></div><span class="propagation-op">×</span><div class="propagation-term"><span class="propagation-symbol">M<sub>Part</sub></span><span class="propagation-value">回転 +20°</span><small>さらに、パーツのピボットを中心に</small></div><span class="propagation-op propagation-op-eq">＝</span><div class="propagation-term propagation-term-result"><span class="propagation-symbol">M<sub>Final</sub></span><span class="propagation-value">向き +45°</span><small>向きは合計45°になる一方、描画位置は各ピボットの位置関係で決まり、単純な足し合わせにはならない</small></div><div class="propagation-demo"><div class="propagation-orbit" aria-hidden="true"><span class="propagation-ring propagation-ring-g"></span><span class="propagation-sun"></span><div class="propagation-system-g"><div class="propagation-earth-system"><span class="propagation-ring propagation-ring-c"></span><span class="propagation-earth"></span><div class="propagation-system-c"><span class="propagation-moon"></span></div></div></div></div><div class="propagation-orbit-copy"><ul class="propagation-legend"><li><span class="propagation-legend-dot propagation-legend-sun"></span>太陽 ＝ Global（テキスト全体）</li><li><span class="propagation-legend-dot propagation-legend-earth"></span>地球 ＝ Character（文字ごと）</li><li><span class="propagation-legend-dot propagation-legend-moon"></span>月 ＝ Part（パーツごと）</li></ul><p class="propagation-demo-caption">地球は太陽のまわりを回り、月はさらに地球のまわりを回ります。それぞれは自分の軸を中心に素直に回っているだけでも、太陽から見た月の位置と向きは、すべての回転が掛け合わさった複雑な軌跡を描きます。Global・Character・Part の変形もこれと同じ仕組みで、各レベルのピボットを中心とした変形が順に掛け合わさって最終的な描画位置・向きが決まります。</p></div></div></div><p><img src="'+r+'" alt="Global・Character・Part それぞれのレベルで変形が加わる様子"></p><p><em>Global → Character → Part の順に変形が積み重なる様子</em></p><p><strong>色の合成</strong>についても同様の優先順位があります。詳細は付録の「<a href="/mug-typography-docs/reference/appendix.html#色の優先順位">色の優先順位</a>」を参照してください。</p><h2 id="パーツ操作が不要な場合" tabindex="-1">パーツ操作が不要な場合 <a class="header-anchor" href="#パーツ操作が不要な場合" aria-label="Permalink to &quot;パーツ操作が不要な場合&quot;">​</a></h2><p>パーツ単位での操作（移動・拡大縮小など）を使わない場合は、Lite版を選択することでクリップのロードや選択動作を軽くできます。Part Settings がインスペクタから省略され、項目数が減るためです。</p><p>目的に合ったプリセットを選ぶことが重要です。詳しくは「<a href="/mug-typography-docs/guide/getting-started.html">使い方</a>」を参照してください。</p><h2 id="インデックスの見方" tabindex="-1">インデックスの見方 <a class="header-anchor" href="#インデックスの見方" aria-label="Permalink to &quot;インデックスの見方&quot;">​</a></h2><p>Character Settings の <code>Character 1, 2...</code> は、入力テキストの先頭から数えた文字番号です。Part Settings の <code>Part Setting 1, 2...</code> は、全文字のパーツを通した番号です。これらは Output Settings や Animation Settings の Targets で使う <code>c1</code>、<code>p1</code> と対応します。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Inspector の各項目には実際の文字と、その文字内で何番目のパーツかが表示されます。番号だけで判断しづらい場合は、ビューアで対象を選択して対応する項目を確認してください。</p></div><hr><p><a id="interface-overview-ja"></a></p>',18)])])}const u=t(n,[["render",e]]);export{m as __pageData,u as default};
